---
import type { HTMLAttributes } from "astro/types";
import { cn } from "@/lib/utils";

interface Props extends HTMLAttributes<"div"> {
  disabled?: boolean;
  inset?: boolean;
  value?: string;
  class?: string;
}

const {
  disabled = false,
  inset = false,
  value,
  class: className = "",
  ...rest
} = Astro.props as Props;
---

<div
  {...rest}
  role="menuitem"
  tabindex={disabled ? -1 : 0}
  data-slot="dropdown-menu-item"
  data-value={value}
  data-disabled={disabled ? "" : undefined}
  data-inset={inset ? "" : undefined}
  class={cn(
    "focus:bg-accent focus:text-accent-foreground data-[variant=destructive]:text-destructive data-[variant=destructive]:focus:bg-destructive/10 dark:data-[variant=destructive]:focus:bg-destructive/20 data-[variant=destructive]:focus:text-destructive data-[variant=destructive]:*:[svg]:text-destructive not-data-[variant=destructive]:focus:**:text-accent-foreground gap-1.5 rounded-md px-1.5 py-1 text-sm data-inset:pl-7 [&_svg:not([class*='size-'])]:size-4",
    "group/dropdown-menu-item relative flex cursor-default items-center outline-hidden select-none data-[disabled]:pointer-events-none data-[disabled]:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0",
    className,
  )}
>
  <slot />
</div>

